var e=e=>{if(e==null||Number.isNaN(e))return`0`;let t=Math.abs(e);return t>=1e6?(e/1e6).toFixed(t%1e6==0?0:1)+`M`:t>=1e3?(e/1e3).toFixed(t%1e3==0?0:1)+`K`:String(e)},t=e=>{try{return new Date(e).toLocaleDateString(`en-US`,{month:`short`,day:`numeric`,year:`numeric`})}catch{return e}},n=e=>{let n=Date.now()-new Date(e).getTime(),r=Math.round(n/6e4);if(r<1)return`just now`;if(r<60)return`${r}m ago`;let i=Math.round(r/60);if(i<24)return`${i}h ago`;let a=Math.round(i/24);return a<30?`${a}d ago`:t(e)};export{e as n,n as r,t};